     1â†’/**
     2â†’ * Mens HRT Enhanced PDP 1
     3â†’ * Page-specific JavaScript for page-mens-hrt-enhanced-pdp-1.php
     4â†’ * 
     5â†’ * Autoplay first video when the section scrolls into view
     6â†’ */
     7â†’
     8â†’// Import utilities
     9â†’import { initCarousel } from '../utilities/carousel.js';
    10â†’
    11â†’// Export to window for global access
    12â†’window.initCarousel = initCarousel;
    13â†’
    14â†’/**
    15â†’ * How It Works â€” click-to-play video cards
    16â†’ * - Thumbnail shows by default as placeholder
    17â†’ * - On click: lazy-load video src, play, hide thumbnail
    18â†’ * - Clicking a playing video pauses it
    19â†’ * - Only one video plays at a time
    20â†’ */
    21â†’function initSocialVideos() {
    22â†’	const items = document.querySelectorAll('.how-it-works.social-videos .review-video-item');
    23â†’	const loadedMap = new WeakMap();
    24â†’
    25â†’	function loadAndPlay(item) {
    26â†’		const video = item.querySelector('video');
    27â†’		if (!video) return;
    28â†’
    29â†’		items.forEach((other) => {
    30â†’			if (other !== item) stopVideo(other);
    31â†’		});
    32â†’
    33â†’		if (!loadedMap.get(video)) {
    34â†’			const lazySrc = video.getAttribute('data-src');
    35â†’			if (!lazySrc) return;
    36â†’			video.src = lazySrc;
    37â†’			video.load();
    38â†’			loadedMap.set(video, true);
    39â†’		}
    40â†’
    41â†’		video.play().then(() => {
    42â†’			item.classList.add('playing');
    43â†’		}).catch(() => {});
    44â†’	}
    45â†’
    46â†’	function stopVideo(item) {
    47â†’		const video = item.querySelector('video');
    48â†’		if (!video) return;
    49â†’		video.pause();
    50â†’		item.classList.remove('playing');
    51â†’	}
    52â†’
    53â†’	items.forEach((item) => {
    54â†’		const video = item.querySelector('video');
    55â†’		const muteBtn = item.querySelector('.mute-toggle');
    56â†’		if (!video) return;
    57â†’
    58â†’		item.addEventListener('click', () => {
    59â†’			if (item.classList.contains('playing')) {
    60â†’				stopVideo(item);
    61â†’			} else {
    62â†’				loadAndPlay(item);
    63â†’			}
    64â†’		});
    65â†’
    66â†’		if (muteBtn) {
    67â†’			muteBtn.addEventListener('click', (e) => {
    68â†’				e.stopPropagation();
    69â†’				const shouldUnmute = video.muted;
    70â†’
    71â†’				if (shouldUnmute) {
    72â†’					items.forEach((other) => {
    73â†’						const otherVideo = other.querySelector('video');
    74â†’						if (otherVideo && otherVideo !== video) {
    75â†’							otherVideo.muted = true;
    76â†’							other.classList.remove('unmuted');
    77â†’							const otherBtn = other.querySelector('.mute-toggle');
    78â†’							if (otherBtn) otherBtn.setAttribute('aria-label', 'Unmute video');
    79â†’						}
    80â†’					});
    81â†’				}
    82â†’
    83â†’				video.muted = !shouldUnmute;
    84â†’				item.classList.toggle('unmuted', shouldUnmute);
    85â†’				muteBtn.setAttribute('aria-label', shouldUnmute ? 'Mute video' : 'Unmute video');
    86â†’			});
    87â†’		}
    88â†’	});
    89â†’
    90â†’	// Autoplay first video when the section scrolls into view
    91â†’	const firstItem = items[0];
    92â†’	if (firstItem) {
    93â†’		const observer = new IntersectionObserver((entries) => {
    94â†’			entries.forEach((entry) => {
    95â†’				if (entry.isIntersecting) {
    96â†’					loadAndPlay(firstItem);
    97â†’					observer.disconnect();
    98â†’				}
    99â†’			});
   100â†’		}, { threshold: 0.3 });
   101â†’
   102â†’		observer.observe(firstItem);
   103â†’	}
   104â†’}
   105â†’
   106â†’jQuery(document).ready(function($) {		
   107â†’	// Testimonials carousel
   108â†’	const testimonialsParams = {
   109â†’		slidesToShow: 3,
   110â†’		infinite: true,
   111â†’		centerMode: true,
   112â†’		responsive: [
   113â†’			{
   114â†’				breakpoint: 1024,
   115â†’				settings: {
   116â†’					slidesToShow: 1,
   117â†’					centerPadding: '8rem',
   118â†’				}
   119â†’			},
   120â†’			{
   121â†’				breakpoint: 600,
   122â†’				settings: {
   123â†’					slidesToShow: 1,
   124â†’					centerPadding: '1rem',
   125â†’				}
   126â†’			}
   127â†’		]
   128â†’	};
   129â†’	initCarousel(testimonialsParams, '.testimonials');
   130â†’
   131â†’	// Injections gallery â€” native scroll carousel + clickable thumbnail nav (tablet/mobile)
   132â†’	const mainCarousel = document.querySelector('.injections-main-carousel');
   133â†’	if (mainCarousel) {
   134â†’		const slides = mainCarousel.querySelectorAll('.slide');
   135â†’		const thumbs = document.querySelectorAll('.injections-thumbs .thumb');
   136â†’
   137â†’		function getSlideByIndex(idx) {
   138â†’			return mainCarousel.querySelector('.slide[data-slide="' + idx + '"]');
   139â†’		}
   140â†’
   141â†’		function updateActiveThumb(dataIndex) {
   142â†’			thumbs.forEach(t => t.classList.remove('active'));
   143â†’			const match = document.querySelector('.injections-thumbs .thumb[data-slide="' + dataIndex + '"]');
   144â†’			if (match) match.classList.add('active');
   145â†’		}
   146â†’
   147â†’		function scrollToSlide(slide) {
   148â†’			mainCarousel.style.scrollSnapType = '';
   149â†’			mainCarousel.scrollTo({ left: slide.offsetLeft, behavior: 'smooth' });
   150â†’		}
   151â†’
   152â†’		thumbs.forEach(thumb => {
   153â†’			thumb.addEventListener('click', () => {
   154â†’				const index = parseInt(thumb.dataset.slide, 10);
   155â†’				const slide = getSlideByIndex(index);
   156â†’				if (slide) {
   157â†’					updateActiveThumb(index);
   158â†’					scrollToSlide(slide);
   159â†’				}
   160â†’			});
   161â†’		});
   162â†’
   163â†’		let scrollTimeout;
   164â†’		mainCarousel.addEventListener('scroll', () => {
   165â†’			clearTimeout(scrollTimeout);
   166â†’			scrollTimeout = setTimeout(() => {
   167â†’				const scrollLeft = mainCarousel.scrollLeft;
   168â†’				let closestSlide = slides[0];
   169â†’				let closestDist = Infinity;
   170â†’				slides.forEach(slide => {
   171â†’					const dist = Math.abs(slide.offsetLeft - scrollLeft);
   172â†’					if (dist < closestDist) {
   173â†’						closestDist = dist;
   174â†’						closestSlide = slide;
   175â†’					}
   176â†’				});
   177â†’				updateActiveThumb(parseInt(closestSlide.dataset.slide, 10));
   178â†’			}, 50);
   179â†’		});
   180â†’
   181â†’		// Mouse drag-to-scroll
   182â†’		let isDragging = false;
   183â†’		let startX = 0;
   184â†’		let scrollStart = 0;
   185â†’
   186â†’		mainCarousel.addEventListener('mousedown', (e) => {
   187â†’			isDragging = true;
   188â†’			startX = e.pageX;
   189â†’			scrollStart = mainCarousel.scrollLeft;
   190â†’			mainCarousel.style.cursor = 'grabbing';
   191â†’			mainCarousel.style.scrollSnapType = 'none';
   192â†’			e.preventDefault();
   193â†’		});
   194â†’
   195â†’		window.addEventListener('mousemove', (e) => {
   196â†’			if (!isDragging) return;
   197â†’			const dx = e.pageX - startX;
   198â†’			mainCarousel.scrollLeft = scrollStart - dx;
   199â†’		});
   200â†’
   201â†’		window.addEventListener('mouseup', () => {
   202â†’			if (!isDragging) return;
   203â†’			isDragging = false;
   204â†’			mainCarousel.style.cursor = '';
   205â†’			mainCarousel.style.scrollSnapType = '';
   206â†’		});
   207â†’
   208â†’		updateActiveThumb(0);
   209â†’	}
   210â†’});
   211â†’
   212â†’/**
   213â†’ * Benefits Timeline â€” click-to-expand cards
   214â†’ * Like https://get.timeline.com/meta/gummies .framer-wd2b1m
   215â†’ * - First card starts active (expanded with full text)
   216â†’ * - Clicking a card makes it active, others collapse
   217â†’ * - Active: wider, full opacity, shows heading + body
   218â†’ * - Inactive: narrower, 0.8 opacity, only shows day label
   219â†’ */
   220â†’function initBenefitsTimeline() {
   221â†’	const cards = document.querySelectorAll('.benefits-timeline .timeline-card');
   222â†’	if (!cards.length) return;
   223â†’
   224â†’	// Set first card as active by default
   225â†’	cards[0].classList.add('active');
   226â†’
   227â†’	cards.forEach((card) => {
   228â†’		card.addEventListener('click', () => {
   229â†’			// Remove active from all cards
   230â†’			cards.forEach((c) => c.classList.remove('active'));
   231â†’			// Set clicked card as active
   232â†’			card.classList.add('active');
   233â†’		});
   234â†’	});
   235â†’}
   236â†’
   237â†’/**
   238â†’ * FAQ Accordion
   239â†’ * - Click header to toggle open/close
   240â†’ * - Only one item open at a time (optional, currently allows multiple)
   241â†’ */
   242â†’function initFaqAccordion() {
   243â†’	const items = document.querySelectorAll('.faq-block .faq-item');
   244â†’	if (!items.length) return;
   245â†’
   246â†’	items.forEach((item) => {
   247â†’		const header = item.querySelector('.faq-header');
   248â†’		if (!header) return;
   249â†’
   250â†’		header.addEventListener('click', () => {
   251â†’			const isOpen = item.classList.contains('open');
   252â†’
   253â†’			// Close all other items
   254â†’			items.forEach((other) => other.classList.remove('open'));
   255â†’
   256â†’			// Toggle clicked item
   257â†’			if (!isOpen) {
   258â†’				item.classList.add('open');
   259â†’				header.setAttribute('aria-expanded', 'true');
   260â†’			} else {
   261â†’				header.setAttribute('aria-expanded', 'false');
   262â†’			}
   263â†’		});
   264â†’	});
   265â†’}
   266â†’
   267â†’function initMarquee() {
   268â†’	const marquee = document.querySelector('.marquee.trustpilot-ratings .reviews-marquee');
   269â†’	const firstSet = marquee?.querySelector('.reviews-set');
   270â†’	if (!marquee || !firstSet) return;
   271â†’
   272â†’	const setWidth = firstSet.getBoundingClientRect().width;
   273â†’	marquee.style.setProperty('--marquee-offset', `-${setWidth}px`);
   274â†’}
   275â†’
   276â†’document.addEventListener('DOMContentLoaded', () => {
   277â†’	initSocialVideos();
   278â†’	initBenefitsTimeline();
   279â†’	initFaqAccordion();
   280â†’	initMarquee();
   281â†’});
